// Descobre o tipo do arquivo (PDF x planilha) e guarda metadados.
const item = $input.first();
const bin = (item.binary && item.binary.data) || {};
const name = (bin.fileName || '').toString().toLowerCase();
const mime = (bin.mimeType || '').toString().toLowerCase();
let kind = 'spreadsheet';
if (name.endsWith('.pdf') || mime.includes('pdf')) kind = 'pdf';
return [{ json: { kind, arquivo: bin.fileName || 'Relatório' }, binary: item.binary }];

// Detecta automaticamente Inventário x Necessidades e normaliza as linhas
// conforme o layout real dos relatórios do ERP da Welmy.
const detect = $('Detect Kind').first().json || {};
const arquivo = detect.arquivo || 'Relatório';
const items = $input.all();
const first = items[0] && items[0].json;
const isPdf = !!(first && typeof first.text === 'string' && first.text.length > 40);

function parseInventarioPdf(text) {
  const rows = [];
  let grupo = null;
  const reGrupo = /Grupo de Estoque\s*:?\s*(.+)/i;
  // NCM  codigo - descricao  qtd  und  valorUnit  valorTotal
  const reItem = /^(\d[\d.]*)\s+(\S.*?)\s+([\d.]+,\d+)\s+([A-Za-z]{1,3})\s+([\d.]+,\d+)\s+([\d.]+,\d+)$/;
  for (const raw of text.split(/\r?\n/)) {
    const line = (raw || '').trim();
    if (!line) continue;
    if (/^Total\b/i.test(line)) continue;
    const g = line.match(reGrupo);
    if (g) { grupo = g[1].trim(); continue; }
    const m = line.match(reItem);
    if (!m) continue;
    const rest = m[2].trim();
    const dash = rest.indexOf(' - ');
    if (dash < 0) continue;
    rows.push({
      ncm: m[1].trim(),
      codigo: rest.slice(0, dash).trim(),
      descricao: rest.slice(dash + 3).trim(),
      quantidade: m[3], unidade: m[4], valor_unitario: m[5], grupo
    });
  }
  return rows;
}

function parseNecessidadesPdf(text) {
  const rows = [];
  let secao = null;
  // O pdf-parse do n8n (v1.x) extrai os numeros COLADOS (sem espaco) e o C/F no
  // meio da linha; outras versoes separam por espaco. Este parser tolera os dois.
  // Cada numero tem sempre 4 casas decimais (BR: 1.200,0000). Layout por item:
  //   CODIGO - DESCRICAO+UND <n1..n9> C|F <n10>
  //   n9 (ultimo antes do C/F) = Necessidade final (liquida do ERP);
  //   n8 = Total Saidas (bruta); n1 = Ped. Compra;
  //   n10 (apos o C/F) = Est. Disp + Alo (estoque atual).
  const UNITS = ['PC','UN','KG','M2','M3','MT','LT','CX','PR','PT','RL','CJ','GR','ML','BR','MM','CM','M'];
  const reNum = /-?\d{1,3}(?:\.\d{3})*,\d{4}/g;
  const reItem = /^(\S+)\s*-\s*(.*?,\d{4})\s*([CF])\s*(-?\d{1,3}(?:\.\d{3})*,\d{4})\s*$/;
  for (const raw of text.split(/\r?\n/)) {
    const line = (raw || '').trim();
    if (!line) continue;
    if (/ITENS\s+PAIS/i.test(line)) { secao = 'fabricado'; continue; }
    if (/ITENS\s+A\s+COMPRAR/i.test(line)) { secao = 'comprado'; continue; }
    if (/ITENS\s+A\s+FABRICAR/i.test(line)) { secao = 'fabricado'; continue; }
    const m = line.match(reItem);
    if (!m) continue;
    const nums = (m[2].match(reNum) || []);
    if (nums.length < 2) continue;
    const cf = m[3];
    let descUnid = m[2].replace(reNum, '').trim();
    let unidade = '';
    for (const u of UNITS) {
      if (descUnid.toUpperCase().endsWith(u)) { unidade = u; descUnid = descUnid.slice(0, descUnid.length - u.length).trim(); break; }
    }
    rows.push({
      codigo: m[1].trim(),
      descricao: descUnid,
      unidade,
      grupo: cf === 'F' ? 'fabricado' : (cf === 'C' ? 'comprado' : secao),
      estoque_atual: m[4],
      pedido_aberto_qtd: nums[0] || '0',
      necessidade_bruta: nums[nums.length - 2],
      necessidade: nums[nums.length - 1]
    });
  }
  return rows;
}

let tipo = 'desconhecido';
let rows = [];

if (isPdf) {
  const text = first.text;
  if (/REGISTRO DE INVENT[ÁA]RIO/i.test(text) || /Grupo de Estoque/i.test(text)) {
    tipo = 'inventario'; rows = parseInventarioPdf(text);
  } else if (/RELAT[ÓO]RIO DE NECESSIDADES/i.test(text) || /Necessidade/i.test(text)) {
    tipo = 'necessidades'; rows = parseNecessidadesPdf(text);
  }
} else {
  const norm = items.map((i) => i.json).filter((o) => o && Object.keys(o).length).map((o) => {
    const out = {}; for (const k of Object.keys(o)) out[k.toString().trim().toLowerCase().replace(/\s+/g, '_')] = o[k]; return out;
  });
  const keys = norm.length ? Object.keys(norm[0]).join(' ') : '';
  if (/necessidade|saidas|requisitado/.test(keys)) { tipo = 'necessidades'; rows = norm; }
  else if (/quantidade|estoque|saldo/.test(keys) && /valor|grupo|classifica|ncm/.test(keys)) { tipo = 'inventario'; rows = norm; }
  else { tipo = 'desconhecido'; rows = norm; }
}

const meta = ($('Receive Relatorio').first().json.body) || {};
const comp = (meta.competencia || '').toString().trim();
const competencia = comp ? (comp.length === 7 ? comp + '-01' : comp) : null;

let amostra_linhas = [];
if (isPdf && rows.length === 0) {
  amostra_linhas = first.text.split(/\r?\n/).map((l) => (l || '').trim()).filter((l) => /\s-\s/.test(l)).slice(0, 15);
}

return [{ json: {
  tipo, arquivo,
  label: (meta.label || '').toString().trim() || (tipo === 'inventario' ? 'Registro de Inventário' : 'Relatório de Necessidades'),
  competencia,
  total_linhas: rows.length,
  amostra_linhas,
  rows
} }];
